sql:
SELECT COUNT(*) AS total_datasets
FROM derived_mini_closure
WHERE max_d_close > 50;

SELECT model_training_file_name, model_training_file_path 
FROM model_training_files
WHERE model_training_file_id = 0;

SELECT test_drive_name, test_drive_location
FROM test_drives
WHERE test_drive_id = 1;

SELECT dataset_id, data_type
FROM datasets
WHERE data_type = 'radar';

SELECT datasets.dataset_id, dataset_tags.tag_name, dataset_tags.tag_description
FROM datasets
LEFT JOIN dataset_tags ON datasets.dataset_id = dataset_tags.dataset_id;

SELECT COUNT(DISTINCT df.dataset_id) 
FROM dataset_filters df
WHERE df.filter_name = 'filter2';

SELECT dataset_id
FROM dataset_quality_metrics
WHERE metric_name = 'MetricName' AND metric_value > 0.8;

