; The term "data collection method" refers to a unique approach or technique used for gathering data; 
; A "dataset" is a collection of related data; 
; In this context, the number of datasets associated with a method is an indicator of how frequently that method is used.

sql:
SELECT DISTINCT dt.data_type_name
FROM datasets ds
JOIN data_types dt ON ds.data_type = dt.data_type_id;

SELECT dataset_id, data_type, model_training_file 
FROM datasets 
WHERE data_type = 'radar';

SELECT dataset_id, max_d_close
FROM gt_vicinity
WHERE max_d_close >= 20 AND max_d_close <= 30;
